const rec = $('Get Company by ID').item.json;
const exa = $('Resolve Domain').item.json || {};

const DIRECTORY_DOMAINS = [
  'linkedin.com', 'crunchbase.com', 'sec.gov', 'wikipedia.org', 'wikidata.org',
  'patsnap.com', 'synapse.patsnap.com', 'orpha.net', 'acnnewswire.com',
  'cgtlive.com', 'fiercebiotech.com', 'fiercepharma.com', 'biospace.com',
  'bloomberg.com', 'reuters.com', 'pitchbook.com', 'zoominfo.com',
  'glassdoor.com', 'indeed.com', 'youtube.com', 'facebook.com',
  'twitter.com', 'x.com', 'medium.com', 'prnewswire.com',
  'businesswire.com', 'newswire.com', 'globenewswire.com', 'pressrelease.com',
  'tracxn.com', 'rocketreach.co', 'apollo.io', 'biopharmadive.com',
  'firstwordpharma.com', 'cirm.ca.gov', 'forbion.com',
  'company-information.service.gov.uk', 'navigator.reaganudall.org',
  'clinicaltrials.gov'
];

function hostname(url) {
  if (typeof url !== 'string' || !url) return '';
  let s = url.replace(/^https?:\/\//i, '');
  s = s.split('/')[0].split('?')[0].split('#')[0];
  s = s.replace(/^.*@/, '').split(':')[0];
  s = s.replace(/^www\./i, '');
  return s.toLowerCase().trim();
}
function isDirectory(host) {
  return DIRECTORY_DOMAINS.some(d => host === d || host.endsWith('.' + d));
}

const results = Array.isArray(exa.results) ? exa.results : [];
let resolved = '';
const debugUrls = [];
for (const r of results) {
  const u = r && r.url;
  const h = hostname(u);
  const dir = h ? isDirectory(h) : false;
  debugUrls.push({ url: u, host: h, directory: dir });
  if (!h) continue;
  if (dir) continue;
  resolved = h;
  break;
}

const isUsable = !!resolved && resolved.includes('.') && !/\s/.test(resolved);
const original = rec.fields && rec.fields.Domain ? rec.fields.Domain : '';
const newDomain = isUsable ? resolved : original;

return { json: {
  ...rec,
  fields: { ...rec.fields, Domain: newDomain },
  _resolvedDomain: resolved || null,
  _domainResolutionUsed: isUsable,
  _originalDomain: original || null,
  _resolverSource: isUsable ? 'exa' : (original ? 'original' : 'none'),
  _exaResultCount: results.length,
  _exaDebug: debugUrls
} };

