site","explorium_testing_and_qa","explorium_text_results","explorium_time_on_site","explorium_total_reviews_count","explorium_ultimate_parent_id","explorium_ultimate_parent_name","explorium_umbrella","explorium_unknown_channel","explorium_url","explorium_users","explorium_visits","explorium_payload_truncated"]);

// Explorium native node outputs: { enrichmentsResponse: [...], enriched_data: [ {business_id, data: {<flat firmographics+tech+...>}} ] }
function pickEnrichRoot(j) {
  if (!j || typeof j !== 'object') return null;
  // Native Explorium API node shape
  if (Array.isArray(j.enriched_data) && j.enriched_data[0]) {
    const e = j.enriched_data[0];
    // .data is the merged enrichment payload; lift business_id alongside.
    return { business_id: e.business_id, ...(e.data || {}) };
  }
  // Fallback shapes (MCP / raw REST)
  if (Array.isArray(j.data) && j.data[0]) return j.data[0];
  if (j.response && Array.isArray(j.response.data) && j.response.data[0]) return j.response.data[0];
  if (j.business_id || j.firmographics) return j;
  return null;
}

const root = pickEnrichRoot($json);
const flat = {};
if (root && typeof root === 'object') {
  for (const [k, v] of Object.entries(root)) {
    if (v && typeof v === 'object' && !Array.isArray(v)) {
      // Section objects (firmographics: {...}) — pull keys up to top level
      for (const [sk, sv] of Object.entries(v)) flat[sk] = sv;
    } else {
      flat[k] = v;
    }
  }
}

const src = $('Get Company by ID').first().json;
const businessId = flat.business_id || root?.business_id || null;
const matched = !!businessId;
const toCellValue = (v) => {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'object') return JSON.stringify(v);
  return v;
};
const parseNum = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
};

const fields = {
  id: src.id,
  'Trigger': 'Done',
  'Enrichment Status':         matched ? 'enrichment_complete' : 'enrichment_incomplete',
  'Industry':                  flat.naics_description || null,
  'Revenue Range':             flat.yearly_revenue_range || null,
  'HQ Country':                flat.country_name || flat.country || null,
  'HQ State':                  flat.region_name || flat.state || null,
  'HQ City':                   flat.city_name || flat.city || null,
  'Company LinkedIn URL':      flat.linkedin_url || flat.linkedin_profile || null,
  'Employee Range':            flat.number_of_employees_range || null,
  'NAICS Code':                flat.naics || null,
  'Explorium Business ID':     businessId,
  'Stock Ticker':              flat.ticker || null,
  'Founded Year':              parseNum(flat.year_founded || flat.founded_year || flat.founded),
  'Last Funding Amount USD':   parseNum(flat.last_funding_round_value_usd),
  'Last Funding Date':         flat.last_funding_round_date || null,
  'Total Known Funding USD':   parseNum(flat.known_funding_total_value),
  'Number of Funding Rounds':  parseNum(flat.number_of_funding_rounds)
};

for (const [k, v] of Object.entries(flat)) {
  const col = 'explorium_' + k;
  if (!SAFE.has(col)) continue;
  if (v === null || v === undefined || v === '') continue;
  let cell;
  if (typeof v === 'object') cell = JSON.stringify(v);
  else if (typeof v === 'boolean') cell = v ? 'true' : 'false';
  else cell = String(v);
  fields[col] = cell;
}

// Write the Exa-resolved domain back to Airtable, but only if Exa actually produced one
// (otherwise keep the existing Domain field untouched).
try {
  const applied = $('Apply Resolved Domain').first().json;
  if (applied && applied._domainResolutionUsed && applied._resolvedDomain) {
    fields['Domain'] = 'https://' + applied._resolvedDomain;
  }
} catch (e) { /* node not in path, skip */ }


// === Pretty top-level synthesis fields (multilineText) ===
function toMultilineBullets(v) {
  if (v === null || v === undefined || v === '') return null;
  if (Array.isArray(v)) {
    const items = v.filter(x => x !== null && x !== undefined && x !== '');
    if (items.length === 0) return null;
    return items.map(x => '- ' + (typeof x === 'string' ? x : JSON.stringify(x))).join('\n');
  }
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}
const kc = toMultilineBullets(flat.key_competitors);
if (kc) fields['Key Competitors'] = kc;
const cf = toMultilineBullets(flat.company_focus);
if (cf) fields['Company Focus'] = cf;

const STRATEGIC_SECTIONS = [
  ['competitive_differentiation', 'Competitive Differentiation'],
  ['company_value_proposition',   'Value Proposition'],
  ['target_market',               'Target Market'],
  ['technological_disruption',    'Technological Disruption'],
  ['company_market_saturation',   'Market Saturation'],
  ['company_partnerships',        'Partnerships'],
  ['company_product_development', 'Product Development'],
  ['company_marketing_sales',     'Marketing & Sales'],
  ['company_customer_adoption',   'Customer Adoption'],
  ['company_data_security_breach','Data Security Risk'],
  ['company_data_security_privacy','Data Privacy Compliance'],
  ['change_description',          'Recent Change'],
  ['change_implication',          'Change Implication']
];
const strategicParts = [];
for (const [k, label] of STRATEGIC_SECTIONS) {
  const v = flat[k];
  if (v === null || v === undefined || v === '') continue;
  let body;
  if (Array.isArray(v)) {
    const items = v.filter(x => x !== null && x !== undefined && x !== '');
    if (items.length === 0) continue;
    body = items.map(x => '- ' + (typeof x === 'string' ? x : JSON.stringify(x))).join('\n');
  } else if (typeof v === 'object') {
    body = JSON.stringify(v);
  } else {
    body = String(v);
  }
  strategicParts.push('## ' + label + '\n' + body);
}
if (strategicParts.length > 0) fields['Strategic Notes'] = strategicParts.join('\n\n');

for (const k of Object.keys(fields)) {
  if (fields[k] === null || fields[k] === undefined) delete fields[k];
}
return { json: fields };

// Build Enrichment Run payload for the Enrichment Runs table.
const company  = ($('Get Company by ID').first()?.json) || {};
const fieldsIn = company.fields || {};
const companyName = fieldsIn['Company Name'] || '';
const play       = fieldsIn['Play'] || '';

const mapped = ($('Map to Airtable Fields').first()?.json) || {};
const matched = mapped['Enrichment Status'] === 'enrichment_complete';

const recordsIn  = 1;
const recordsOut = matched ? 1 : 0;

const eid = (typeof $execution !== 'undefined' && $execution && $execution.id)
  || (typeof $executionId !== 'undefined' ? $executionId : '');
const today  = new Date().toISOString().slice(0, 10);
const nowIso = new Date().toISOString();

return {
  json: {
    Name: `Explorium Enrichment - ${companyName || 'unknown'} - ${today}`,
    Status: 'Done',
    'Run Date': nowIso,
    Play: play || '',
    'Gate Version': 'explorium-enrichment-v1',
    'Companies Evaluated': 1,
    'Records In': recordsIn,
    'Records Out': recordsOut,
    'Run Type': 'enrichment',
    'Run Mode': 'incremental',
    'Rules Version': 'explorium-enrichment-v1',
    'Workflow ID': 'LqYwYcastjKq0IJ5',
    'Execution ID': String(eid),
    Providers: ['explorium', 'anthropic'],
    Companies: company.id ? [company.id] : [],
    Notes: matched
      ? `Explorium enrichment for ${companyName}. Matched business_id ${mapped['Explorium Business ID']} (NAICS ${mapped['NAICS Code'] || 'n/a'}).`
      : `Explorium enrichment for ${companyName}. No matching Explorium business found.`,
  }
};
